// // This module subtracts two 32-bit input data signals and a borrow-in signal, producing a difference and a borrow-out signal.
module adder_32bit (
    input [31:0] a,
    input [31:0] b,
    input cin,
    output [31:0] sum,
    output cout
);

assign {cout, sum} = a + b + cin;

endmodule
